import{_ as a,o as t,c as p,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"大唐官府","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/大唐官府.md","filePath":"4.资源分区/6.技艺及称号/武技类/大唐官府.md"}'),o={name:"4.资源分区/6.技艺及称号/武技类/大唐官府.md"};function b(d,e,l,_,i,c){return t(),p("div",null,[...e[0]||(e[0]=[r("h1",{id:"大唐官府",tabindex:"-1"},[n("大唐官府 "),r("a",{class:"header-anchor",href:"#大唐官府","aria-label":'Permalink to "大唐官府"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘003")])])],-1),s('<h1 id="大唐官府-1" tabindex="-1">大唐官府 <a class="header-anchor" href="#大唐官府-1" aria-label="Permalink to &quot;大唐官府&quot;">​</a></h1><p>大唐官府</p><p>大唐子弟曾随唐皇征战天下，立下汗马功劳。门派师傅程咬金更是凌烟阁功臣榜上第一猛将，门下弟子除了修习文韬武略，还对各种兵器了如指掌，其武功招式偏重物理攻击，正应唐皇御笔亲书“天下兵法了于胸，十方无敌勇者狂。”的门派宗旨。<br> 大唐官府的弟子善用刀剑，只有在使用分类为刀、剑的武器时，才能发挥全部效果，在使用非刀剑类的冷兵器时，在计算最终伤害时会降低一半伤害，非武技类专业无法使用此能力。<br> 各技能均需要逐级购买，各级别购买价格均为：D+500/C+1000/B+2000/A+4000</p><p>技能一</p><p>为官之道<br> 大唐官府的基础技能，可以增强弟子的战斗能力与江湖声望。以下效果需逐级购买，且效果叠加计算。<br> D级：增加3点武器伤害，增加10点声望。<br> C级：增加6点破甲，增加3点武器伤害，增加10点声望。<br> B级：获得8加骰，增加6点破甲，增加3点武器伤害，增加10点声望。</p><p>杀气诀<br> 【为官之道】下属技能，需要购买【为官之道】D级之后才可以购买此能力。<br> C级：移动动作使用，为自身周围半径4米范围内的友方单位施加【已掌握的为官之道】，使其可以享受这些效果，持续一场景。ST可以允许声望提升效果不生效。<br> B级：施展动作降低为自由动作，但是该能力多次释放不可叠加，范围提升至48米，持续时间仍为一场景。</p><p>技能二</p><p>无双一击<br> 大唐官府用于提升攻击命中的技能，也可以用于积蓄力量，施展强力一击。<br> D级：增加4点技艺加值。<br> C级：当一次攻击未能命中时，可以重新进行一次检定，并按本次检定进行结算。增加4点技艺加值。</p><p>后发制人<br> C级：【无双一击】下属技能，需要购买【无双一击】D级之后才可以购买此能力，积蓄力量发出强力一击。以下效果需逐级购买，且效果叠加计算。<br> 整轮动作使用，使用此能力后，需要在所有人行动之后进行攻击，在本回合增加自身3点闪避防御附加。在朝向本回合对自身进行攻击过的目标进行攻击时，则会额外增加一次不带招式能量且最终伤害减半的攻击。<br> B级：在本回合受到的攻击如果会使人物死亡，则可以完全抵消本次攻击，这是一个B级别、创伤来源的无敌效果，这一效果每影片只会生效一次。这回合发动的攻击，每拥有2点武器伤害，就可以令本回合进行的攻击忽视目标1点护甲防御。</p><p>技能三</p><p>十方无敌<br> 大唐官府的绝技，其成名技【横扫千军】令天下人闻风丧胆。<br> C级：以标准动作使用刀剑击破目标，进行一次攻击，命中后令其承受持续一个回合的B级别重伤效果。</p><p>横扫千军<br> A级：以标准动作使用，连续对一个目标发动3次攻击，造成大量伤害，之后对自身造成最后一击伤害数10%的冲击点数。如果学习大唐官府技能数为奇数，则对自身扣除等同本技能造成的冲击点数的韧性。<br> 如果在使用这个技能时的当轮或者上轮使用了十方无敌，则横扫千军的最后一次攻击伤害增加一倍，若目标没有完好生命值，则最后一击的伤害再增加一倍。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',14)])])}const m=a(o,[["render",b]]);export{f as __pageData,m as default};
